  ('elementary-10ced7e2-moex-00171', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '在民事訴訟程序中，下列何種事項，法院原則上不應依職權為調查？', '["證明事實之證據", "當事人能力", "審判權之有無", "上訴有無逾期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00172', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於民事訴訟言詞審理原則與公開審理原則，下列敘述何者正確？', '["依民事訴訟法規定，言詞辯論程序，應以訴訟代理人聲明應受裁判之事項為始", "於言詞辯論期日，原告應由本人出席庭期，且不得以手機簡訊截圖、照片、影音或其他文件取代其言詞 陳述", "當事人對於他造提出之事實及證據，應由其訴訟代理人或特別代理人，代為撰狀陳明，以增其攻擊防禦 方法之確實性", "當事人提出之攻擊方法，如涉及當事人隱私，經當事人聲請，法院認為適當者，得不公開審判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00173', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '住所地在臺北之甲，與住所地在桃園之乙及住所地在新竹之丙，三人相約在臺中見面。言談間因細故發生 爭吵，甲遭乙與丙共同毆傷。甲欲依民法侵權行為規定，將乙、丙列為共同被告，請求損害賠償，依民事 訴訟法規定，由何法院管轄？', '["臺灣臺北地方法院", "臺灣桃園地方法院", "臺灣新竹地方法院", "臺灣臺中地方法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00174', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟上和解之敘述，何者錯誤？', '["法院不問訴訟程度如何，得隨時試行和解", "和解成立者，與確定判決有同一之效力", "當事人就未聲明之事項和解成立者，不得為執行名義", "和解有無效或得撤銷之原因者，當事人得請求繼續審判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
