  ('elementary-10ced7e2-moex-00178', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-114-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲委請乙律師擔任訴訟代理人，到法院進行訴訟，就甲與乙間之法律關係，下列敘述何者正確？', '["委任", "僱傭", "承攬", "居間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "509", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
